transform_js:
const data = []; let total = 0;
rawData.rows.forEach(r => {
  data.push({ name: r.name, value: r.value });
  total += r.value;
});
transformedData = { data, total };

echarts_js:
option = {
  tooltip: {
    trigger: 'item'
  },
  legend: {
    top: '5%',
    left: 'center'
  },
  title: {
    text: transformedData.total,
    subtext: 'Total Visits',
    left: 'center',
    top: 'center',
    textStyle: {
      fontSize: 30,
      fontWeight: 'bold'
    }
  },
  series: [
    {
      name: 'Access From',
      type: 'pie',
      radius: ['40%', '70%'],
      avoidLabelOverlap: false,
      itemStyle: {
        borderRadius: 10,
        borderColor: '#fff',
        borderWidth: 2
      },
      label: {
        show: false,
        position: 'center'
      },
      emphasis: {
        label: {
          show: true,
          fontSize: '40',
          fontWeight: 'bold'
        }
      },
      labelLine: {
        show: false
      },
      data: transformedData.data
    }
  ]
};
